PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE Assessment (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    use_case_name TEXT NOT NULL,
    intent_text TEXT NOT NULL,
    overall_score REAL,
    status TEXT DEFAULT 'in_progress',
    created_at TEXT DEFAULT (datetime('now')),
    completed_at TEXT
, client_id INTEGER REFERENCES Client(id), engagement_name TEXT, usecase_id INTEGER REFERENCES Next_UseCase(id), assessment_mode TEXT DEFAULT 'custom', findings_narrative TEXT, consultant_name TEXT, framework_id INTEGER DEFAULT 1);
CREATE TABLE AssessmentCapability (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    assessment_id INTEGER NOT NULL,
    capability_id INTEGER NOT NULL,
    capability_name TEXT NOT NULL,
    domain_name TEXT NOT NULL,
    subdomain_name TEXT NOT NULL,
    capability_role TEXT NOT NULL,
    ai_score REAL,
    rationale TEXT,
    target_maturity INTEGER DEFAULT 3,
    FOREIGN KEY (assessment_id) REFERENCES Assessment(id)
);
CREATE TABLE AssessmentFinding (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    assessment_id INTEGER NOT NULL,
    finding_type TEXT NOT NULL,
    domain TEXT,
    capability_id INTEGER,
    capability_name TEXT,
    capability_role TEXT,
    avg_score REAL,
    target_maturity INTEGER,
    gap REAL,
    risk_level TEXT,
    created_at TEXT DEFAULT (datetime('now')), subdomain TEXT,
    FOREIGN KEY (assessment_id) REFERENCES Assessment(id)
);
CREATE TABLE AssessmentRecommendation (
    id                    INTEGER PRIMARY KEY AUTOINCREMENT,
    assessment_id         INTEGER NOT NULL,
    capability_id         INTEGER,
    capability_name       TEXT,
    domain                TEXT,
    capability_role       TEXT,
    current_score         REAL,
    target_maturity       INTEGER,
    gap                   REAL,
    priority_tier         TEXT,
    effort_estimate       TEXT,
    recommended_actions   TEXT,
    enabling_dependencies TEXT,
    success_indicators    TEXT,
    hpe_relevance         TEXT,
    narrative             TEXT,
    created_at            TEXT,
    FOREIGN KEY (assessment_id) REFERENCES Assessment(id)
);
CREATE TABLE AssessmentResponse (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    assessment_id INTEGER NOT NULL,
    capability_id INTEGER NOT NULL,
    capability_name TEXT NOT NULL,
    domain TEXT NOT NULL,
    subdomain TEXT NOT NULL,
    capability_role TEXT NOT NULL,
    question TEXT NOT NULL,
    response_type TEXT NOT NULL,
    score REAL,
    answer TEXT,
    notes TEXT,
    created_at TEXT DEFAULT (datetime('now')),
    FOREIGN KEY (assessment_id) REFERENCES Assessment(id)
);
CREATE TABLE Client (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    client_name TEXT NOT NULL,
    industry TEXT,
    sector TEXT,
    country TEXT,
    notes TEXT,
    created_at TEXT DEFAULT (datetime('now'))
);
COMMIT;
