INSERT INTO AssessmentCapability VALUES(977,33,325,'GV.RM-01','Govern','Risk Management Strategy','Core',1.0,'Essential for establishing the foundational risk management approach that enables systematic assessment of organizational capabilities against NIST framework requirements.',3);
INSERT INTO AssessmentCapability VALUES(978,33,336,'GV.PO-01','Govern','Policy','Core',0.949999999999999956,'Critical for defining organizational policies that must align with NIST standards and provide the governance structure for compliance assessment.',3);
INSERT INTO AssessmentCapability VALUES(979,33,358,'ID.RA-01','Identify','Risk Assessment','Core',0.9000000000000000222,'Fundamental capability for conducting systematic risk assessments to identify gaps between current state and NIST framework requirements.',3);
INSERT INTO AssessmentCapability VALUES(980,33,320,'GV.OC-01','Govern','Organizational Context','Core',0.9000000000000000222,'Essential for understanding the organizational context and scope that determines which NIST standards are applicable to business operations.',3);
