INSERT INTO AssessmentCapability VALUES(983,33,338,'GV.OV-01','Govern','Oversight','Core',0.8000000000000000444,'Important for establishing governance oversight mechanisms to monitor compliance status and ensure systematic adherence to NIST requirements.',3);
INSERT INTO AssessmentCapability VALUES(984,33,351,'ID.AM-01','Identify','Asset Management','Core',0.8000000000000000444,'Necessary for inventorying and understanding technology infrastructure assets that must be assessed against applicable NIST standards.',3);
INSERT INTO AssessmentCapability VALUES(985,33,326,'GV.RM-02','Govern','Risk Management Strategy','Core',0.75,'Important for operationalizing risk management processes that support ongoing compliance assessment and gap identification activities.',3);
INSERT INTO AssessmentCapability VALUES(986,33,369,'ID.IM-02','Identify','Improvement','Core',0.75,'Valuable for implementing continuous improvement processes that ensure sustained NIST compliance and address emerging requirements.',3);
